import { Decoration, DecorationSet } from "prosemirror-view";

const pluginKey = new PluginKey("uppercaseFirstWord");

function uppercaseFirstWordPlugin(options) {
  return new Plugin({
    key: pluginKey,

    state: {
      init() {
        return DecorationSet.empty;
      },

      apply(tr, set) {
        // Check if the inserted character is a space
        if (tr.docChanged && tr.t().insert.length === 1 && tr.t().insert[0] === " ") {
          // Get the node before the space
          const nodeBefore = tr.doc.nodeBefore(tr.selection.$from.pos);

          // Check if the node before the space is a text node
          if (nodeBefore.type.name === "text") {
            const nodeText = nodeBefore.text;

            // Check if the word before the space is the first word in a sentence
            if (
