              // Get the position and length of the first character in the word
              const firstCharPos = nodeBefore.pos + nodeText.search(/\S/);
              const firstCharLen = nodeText.match(/\S/)[0].length;

              // Create a decoration that highlights the first character in the word
              const decoration = Decoration.inline(
