Creating a full, robust TCP client and server in pure C requires using **socket programming**, which is heavily dependent on the operating system (usually POSIX sockets for Linux/macOS or Winsock for Windows).

Since the code differs significantly between operating systems, I will provide a **POSIX (Linux/macOS) version**, as it is the most common standard for C networking examples.

### Prerequisites (Linux/macOS)

You will need to compile this using a compiler like GCC and you must link the socket library:
```bash
gcc server.c -o server -pthread
gcc client.c -o client
```

---

## 1. TCP Server Prototype (`server.c`)

This server will listen on port 8080, accept one connection, read a message, and send a response back.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

#define PORT 8080
#define BUFFER_SIZE 1024

void error(const char *msg) {
    perror(msg);
    exit(1);
}

int main() {
    int server_fd, new_socket;
    struct sockaddr_in address;
    int addrlen = sizeof(address);
    char buffer[BUFFER_SIZE] = {0};
    const char *hello_message = "Hello from the Server!";

    // 1. Create socket file descriptor
    if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) == 0) {
        error("socket failed");
    }
    printf("Server socket created successfully.\n");

    // Set socket options to reuse address (helpful for quick restarts)
    int opt = 1;
    if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt))) {
        error("setsockopt failed");
    }

    // 2. Define server address structure
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY; // Listen on all available interfaces
    address.sin_port = htons(PORT);

    // 3. Bind the socket to the specified IP and Port
    if (bind(server_fd, (struct sockaddr *)&address, sizeof(address)) < 0) {
        error("bind failed");
    }
    printf("Server bound to port %d.\n", PORT);

    // 4. Listen for incoming connections (max 3 pending connections)
    if (listen(server_fd, 3) < 0) {
        error("listen failed");
    }
    printf("Server listening for connections...\n");

    // 5. Accept a connection
    if ((new_socket = accept(server_fd, (struct sockaddr *)&address, (socklen_t*)&addrlen)) < 0) {
        error("accept failed");
    }
    printf("Connection accepted from client.\n");

    // 6. Read data from the client
    ssize_t valread = read(new_socket, buffer, BUFFER_SIZE - 1);
    if (valread > 0) {
        buffer[valread] = '\0'; // Null-terminate the received string
        printf("Client message received: %s\n", buffer);

        // 7. Send a response back to the client
        send(new_socket, hello_message, strlen(hello_message), 0);
        printf("Response sent to client.\n");
    } else {
        perror("read failed");
    }

    // 8. Close sockets
    close(new_socket);
    close(server_fd);
    printf("Server shutting down.\n");
    return 0;
}
```

---

## 2. TCP Client Prototype (`client.c`)

This client will connect to the server running on `localhost` (127.0.0.1) on port 8080, send a message, and wait for the server's response.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <arpa/inet.h>

#define PORT 8080
#define SERVER_IP "127.0.0.1" // Localhost

void error(const char *msg) {
    perror(msg);
    exit(1);
}

int main() {
    int sock = 0;
    struct sockaddr_in serv_addr;
    char buffer[1024] = {0};
    const char *message_to_send = "Hello Server, I am the client!";

    // 1. Create socket file descriptor
    if ((sock = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
        error("Socket creation error");
    }
    printf("Client socket created successfully.\n");

    // Define server address structure
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_port = htons(PORT);

    // Convert IP address from text to binary form
    if (inet_pton(AF_INET, SERVER_IP, &serv_addr.sin_addr) <= 0) {
        error("Invalid address/ Address not supported");
    }

    // 2. Connect to the server
    if (connect(sock, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
        error("Connection Failed. Ensure the server is running.");
    }
    printf("Successfully connected to the server.\n");

    // 3. Send data to the server
    send(sock, message_to_send, strlen(message_to_send), 0);
    printf("Client sent: \"%s\"\n", message_to_send);

    // 4. Receive response from the server
    ssize_t valread = read(sock, buffer, 1024 - 1);
    if (valread > 0) {
        buffer[valread] = '\0'; // Null-terminate the received string
        printf("Server response received: \"%s\"\n", buffer);
    } else {
        perror("read failed");
    }

    // 5. Close the socket
    close(sock);
    printf("Client disconnected and shut down.\n");
    return 0;
}
```

