        setTimeout(() => {
          span.style.transform = "scale3d(1, 1, 1)";
        }, 1000);
      });
      newlyColoredCount++;
    });
    console.log(`[ACTION] Colored ${newlyColoredCount} new code element(s).`);


    // 2. CLEAN UP REMOVED ELEMENTS
    const initialLength = codeSpans.length;

    // Filter the array: keep the entry only if the parent code element still exists in the DOM
    codeSpans = codeSpans.filter(([code, ...spans]) => {
      if (!document.contains(code)) {
        console.log(`[REMOVE] Code element removed from DOM. Cleaning up entry.`);
        // Optional: Clean up data attributes on removed elements if needed
